export type LeadStatus =
  | 'new'
  | 'contacted'
  | 'confirmed'
  | 'payment1_sent'
  | 'payment1_received'
  | 'receipt1_sent'
  | 'payment2_sent'
  | 'payment2_received'
  | 'receipt2_sent'
  | 'complete';

export type InvoiceStatus = 'draft' | 'sent' | 'paid';

export interface Lead {
  id: string;
  name: string;
  email: string;
  phone: string;
  address: string | null;
  lawn_size: string | null;
  subscription_option: string | null;
  frequency: string | null;
  form_type: string;
  driveway_length: string | null;
  notes: string | null;
  form_data: Record<string, unknown>;
  status: LeadStatus;
  created_at: string;
  updated_at: string;
}

export interface Communication {
  id: string;
  lead_id: string;
  type: string;
  direction: string;
  subject: string | null;
  body: string;
  sent_at: string;
  created_at: string;
}

export interface Invoice {
  id: string;
  lead_id: string;
  description: string;
  amount_cents: number;
  payment_link: string | null;
  status: InvoiceStatus;
  created_at: string;
  sent_at: string | null;
}

export interface EmailTemplate {
  id: string;
  name: string;
  subject: string;
  body: string;
  created_at: string;
  updated_at: string;
}

export const LEAD_STATUS_LABELS: Record<LeadStatus, string> = {
  new: 'New',
  contacted: 'Contacted',
  confirmed: 'Confirmed',
  payment1_sent: 'Payment 1 Sent',
  payment1_received: 'Payment 1 Received',
  receipt1_sent: 'Receipt 1 Sent',
  payment2_sent: 'Payment 2 Sent',
  payment2_received: 'Payment 2 Received',
  receipt2_sent: 'Receipt 2 Sent',
  complete: 'Complete',
};
